import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Trend {
  UP = 'UP',
  DOWN = 'DOWN',
  SIDEWAYS = 'SIDEWAYS'
}

export enum SignalType {
  BREAKOUT = 'BREAKOUT', // 突破
  REVERSAL = 'REVERSAL', // 反转
  MOMENTUM = 'MOMENTUM', // 动能
  OVERSOLD = 'OVERSOLD', // 超卖
  NONE = 'NONE'
}

export interface StockData {
  id: string;
  symbol: string;
  name: string;
  price: number;
  changePercent: number;
  volume: number; // Simulated daily volume
  marketCap: string;
  sector: string;
  rsi: number; // 14-day RSI
  macd: {
    diff: number;
    dea: number;
    histogram: number;
  };
  ma20: number;
  ma50: number;
  ma200: number;
  trend: Trend;
  signal: SignalType;
  history: { time: string; value: number }[]; // For sparklines
}

export interface SniperFilter {
  minRsi: number;
  maxRsi: number;
  minVolume: number;
  signals: SignalType[];
  onlyUptrend: boolean;
}

import { StockData, Trend, SignalType } from './types';

const SECTORS = ['新能源', '半导体', '白酒', '医药', '人工智能', '券商', '房地产'];
const NAMES = [
  '贵州茅台', '宁德时代', '比亚迪', '五粮液', '隆基绿能', 
  '东方财富', '中芯国际', '恒瑞医药', '科大讯飞', '紫光国微',
  '迈瑞医疗', '招商银行', '中国平安', '美的集团', '格力电器',
  '海康威视', '立讯精密', '万华化学', '片仔癀', '韦尔股份'
];

const SYMBOLS = [
  '600519', '300750', '002594', '000858', '601012',
  '300059', '688981', '600276', '002230', '002049',
  '300760', '600036', '601318', '000333', '000651',
  '002415', '002475', '600309', '600436', '603501'
];

const generateHistory = (startPrice: number, points: number = 20) => {
  let current = startPrice;
  const data = [];
  for (let i = 0; i < points; i++) {
    const change = (Math.random() - 0.5) * (startPrice * 0.05);
    current += change;
    data.push({ time: `${i}:00`, value: current });
  }
  return data;
};

export const MOCK_STOCKS: StockData[] = NAMES.map((name, index) => {
  const basePrice = Math.random() * 500 + 10;
  const changeP = (Math.random() * 20) - 10; // -10% to +10%

  // Logic to assign signals based on random indicators
  const rsi = Math.floor(Math.random() * 100);
  let signal = SignalType.NONE;
  let trend = Trend.SIDEWAYS;

  // Simulate Trend
  const ma20 = basePrice * (1 + (Math.random() - 0.5) * 0.1);
  const ma50 = basePrice * (1 + (Math.random() - 0.5) * 0.15);

  if (basePrice > ma20 && ma20 > ma50) trend = Trend.UP;
  else if (basePrice < ma20 && ma20 < ma50) trend = Trend.DOWN;

  // Simulate Signals
  if (changeP > 5 && basePrice > ma20) signal = SignalType.BREAKOUT;
  else if (rsi < 30) signal = SignalType.OVERSOLD;
  else if (rsi > 70 && trend === Trend.UP) signal = SignalType.MOMENTUM;
  else if (changeP > 0 && rsi < 40 && trend === Trend.DOWN) signal = SignalType.REVERSAL;

  return {
    id: SYMBOLS[index],
    symbol: SYMBOLS[index],
    name: name,
    price: parseFloat(basePrice.toFixed(2)),
    changePercent: parseFloat(changeP.toFixed(2)),
    volume: Math.floor(Math.random() * 1000000), // Lots
    marketCap: `${(Math.random() * 2000).toFixed(0)}亿`,
    sector: SECTORS[index % SECTORS.length],
    rsi: rsi,
    macd: {
      diff: Math.random() * 2 - 1,
      dea: Math.random() * 2 - 1,
      histogram: Math.random() * 2 - 1,
    },
    ma20: parseFloat(ma20.toFixed(2)),
    ma50: parseFloat(ma50.toFixed(2)),
    ma200: parseFloat((basePrice * 0.9).toFixed(2)),
    trend: trend,
    signal: signal,
    history: generateHistory(basePrice)
  };
});

import { GoogleGenAI } from "@google/genai";
import { StockData, SignalType } from "../types";

// Initialize the Gemini AI client
// NOTE: In a real app, ensure process.env.API_KEY is available.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeStockWithGemini = async (stock: StockData): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Demo Mode: API Key missing. Please configure your API key to get real AI analysis. Based on technicals: This stock shows " + stock.signal + " characteristics with an RSI of " + stock.rsi + ".";
  }

  const prompt = `
    You are a professional A-Share (Chinese Stock Market) Sniper Analyst. 
    Analyze the following stock data rapidly for a day trader or swing trader.

    Stock: ${stock.name} (${stock.symbol})
    Price: ¥${stock.price}
    Change: ${stock.changePercent}%
    RSI (14): ${stock.rsi}
    Signal Detected: ${stock.signal}
    Trend: ${stock.trend}
    Sector: ${stock.sector}
    MA20: ${stock.ma20}, MA50: ${stock.ma50}

    Provide a concise, bullet-point "Sniper Report" (max 100 words).
    1. Determine "Attack Status": BUY (Snipe), WATCH (Wait), or IGNORE.
    2. Explain the technical rationale (Golden Cross, Oversold bounce, etc.).
    3. Potential risk level (High/Medium/Low).

    Use a professional, urgent, trader tone.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Speed over depth for sniper tool
      }
    });

    return response.text || "Analysis failed.";
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "System Error: Unable to connect to AI Analyst mainframe.";
  }
};

import React from 'react';
import { SniperFilter, SignalType } from '../types';
import { Target, Filter, Zap, Activity } from 'lucide-react';

interface SniperScopeProps {
  filter: SniperFilter;
  setFilter: React.Dispatch<React.SetStateAction<SniperFilter>>;
}

export const SniperScope: React.FC<SniperScopeProps> = ({ filter, setFilter }) => {
  const toggleSignal = (s: SignalType) => {
    if (filter.signals.includes(s)) {
      setFilter(prev => ({ ...prev, signals: prev.signals.filter(i => i !== s) }));
    } else {
      setFilter(prev => ({ ...prev, signals: [...prev.signals, s] }));
    }
  };

  return (
    <div className="bg-crypto-card border border-crypto-border rounded-lg p-4 mb-6 shadow-lg">
      <div className="flex items-center gap-2 mb-4 text-crypto-accent">
        <Target className="w-5 h-5" />
        <h2 className="text-lg font-bold font-mono tracking-wider">SNIPER SCOPE_CONFIG</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Signal Filters */}
        <div className="space-y-2">
          <label className="text-xs text-crypto-muted font-mono uppercase">Strategy Signals</label>
          <div className="flex flex-wrap gap-2">
            {[SignalType.BREAKOUT, SignalType.REVERSAL, SignalType.MOMENTUM, SignalType.OVERSOLD].map((sig) => (
              <button
                key={sig}
                onClick={() => toggleSignal(sig)}
                className={`px-3 py-1 text-xs rounded-full font-bold transition-all border ${
                  filter.signals.includes(sig)
                    ? 'bg-crypto-accent/20 border-crypto-accent text-crypto-accent neon-glow'
                    : 'bg-transparent border-crypto-border text-crypto-muted hover:border-crypto-muted'
                }`}
              >
                {sig}
              </button>
            ))}
          </div>
        </div>

        {/* RSI Slider */}
        <div className="space-y-2">
           <label className="text-xs text-crypto-muted font-mono uppercase flex justify-between">
             <span>RSI Range</span>
             <span className="text-white">{filter.minRsi} - {filter.maxRsi}</span>
           </label>
           <div className="flex gap-2 items-center">
             <span className="text-xs text-crypto-muted">0</span>
             <input 
               type="range" 
               min="0" max="100" 
               value={filter.maxRsi}
               onChange={(e) => setFilter(prev => ({...prev, maxRsi: parseInt(e.target.value)}))}
               className="w-full h-1 bg-crypto-border rounded-lg appearance-none cursor-pointer accent-crypto-accent"
             />
             <span className="text-xs text-crypto-muted">100</span>
           </div>
        </div>

        {/* Trend Toggle */}
        <div className="space-y-2">
           <label className="text-xs text-crypto-muted font-mono uppercase">Trend Context</label>
           <button
            onClick={() => setFilter(prev => ({ ...prev, onlyUptrend: !prev.onlyUptrend }))}
            className={`w-full flex items-center justify-center gap-2 px-4 py-2 rounded border transition-colors ${
              filter.onlyUptrend 
               ? 'bg-crypto-up/10 border-crypto-up text-crypto-up'
               : 'bg-crypto-card border-crypto-border text-crypto-muted'
            }`}
           >
             <Activity className="w-4 h-4" />
             {filter.onlyUptrend ? 'ONLY UPTREND (MA20 > MA50)' : 'ALL TRENDS'}
           </button>
        </div>

         {/* Presets */}
         <div className="space-y-2">
           <label className="text-xs text-crypto-muted font-mono uppercase">Quick Presets</label>
           <div className="flex gap-2">
             <button 
                onClick={() => setFilter({ minRsi: 0, maxRsi: 30, minVolume: 0, signals: [SignalType.OVERSOLD, SignalType.REVERSAL], onlyUptrend: false })}
                className="flex-1 py-1 text-xs bg-crypto-down/10 text-crypto-down border border-crypto-down/30 rounded hover:bg-crypto-down/20"
             >
               Bottom Fish
             </button>
             <button 
                onClick={() => setFilter({ minRsi: 50, maxRsi: 80, minVolume: 0, signals: [SignalType.BREAKOUT], onlyUptrend: true })}
                className="flex-1 py-1 text-xs bg-crypto-up/10 text-crypto-up border border-crypto-up/30 rounded hover:bg-crypto-up/20"
             >
               Moon Shot
             </button>
           </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { StockData, Trend, SignalType } from '../types';
import { TrendingUp, TrendingDown, Minus, Zap, Eye } from 'lucide-react';
import { LineChart, Line, ResponsiveContainer, YAxis } from 'recharts';

interface StockTerminalProps {
  stocks: StockData[];
  onSelectStock: (stock: StockData) => void;
}

export const StockTerminal: React.FC<StockTerminalProps> = ({ stocks, onSelectStock }) => {

  const getTrendIcon = (trend: Trend) => {
    switch (trend) {
      case Trend.UP: return <TrendingUp className="w-4 h-4 text-crypto-up" />;
      case Trend.DOWN: return <TrendingDown className="w-4 h-4 text-crypto-down" />;
      default: return <Minus className="w-4 h-4 text-crypto-muted" />;
    }
  };

  const getSignalBadge = (signal: SignalType) => {
    switch (signal) {
      case SignalType.BREAKOUT: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-crypto-up/20 text-crypto-up border border-crypto-up/40 font-bold animate-pulse">BREAKOUT</span>;
      case SignalType.REVERSAL: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-purple-500/20 text-purple-400 border border-purple-500/40 font-bold">REVERSAL</span>;
      case SignalType.MOMENTUM: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-blue-500/20 text-blue-400 border border-blue-500/40 font-bold">MOMENTUM</span>;
      case SignalType.OVERSOLD: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-orange-500/20 text-orange-400 border border-orange-500/40 font-bold">OVERSOLD</span>;
      default: return null;
    }
  };

  return (
    <div className="bg-crypto-card border border-crypto-border rounded-lg overflow-hidden shadow-lg">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-[#1b2129] border-b border-crypto-border">
            <tr>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase">Symbol / Name</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-right">Price (¥)</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-right">24h Change</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-center">Trend</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-center">RSI(14)</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-center">Sniper Signal</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase w-32">Micro Chart</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-crypto-border/50">
            {stocks.map((stock) => (
              <tr 
                key={stock.id} 
                className="hover:bg-white/5 transition-colors cursor-pointer group"
                onClick={() => onSelectStock(stock)}
              >
                <td className="px-4 py-3">
                  <div className="flex flex-col">
                    <span className="font-bold text-sm text-white group-hover:text-crypto-accent transition-colors">{stock.name}</span>
                    <span className="text-xs text-crypto-muted font-mono">{stock.symbol}</span>
                  </div>
                </td>
                <td className="px-4 py-3 text-right font-mono text-sm">
                  {stock.price.toFixed(2)}
                </td>
                <td className={`px-4 py-3 text-right font-mono text-sm ${stock.changePercent >= 0 ? 'text-crypto-up' : 'text-crypto-down'}`}>
                  {stock.changePercent > 0 ? '+' : ''}{stock.changePercent}%
                </td>
                <td className="px-4 py-3 text-center">
                  <div className="flex justify-center">{getTrendIcon(stock.trend)}</div>
                </td>
                <td className="px-4 py-3 text-center font-mono text-sm">
                  <span className={`${stock.rsi > 70 ? 'text-crypto-down' : stock.rsi < 30 ? 'text-crypto-up' : 'text-crypto-muted'}`}>
                    {stock.rsi}
