import React, { useState, useMemo } from 'react';
import { MOCK_STOCKS } from './constants';
import { StockData, SniperFilter, SignalType } from './types';
import { SniperScope } from './components/SniperScope';
import { StockTerminal } from './components/StockTerminal';
import { AnalysisModal } from './components/AnalysisModal';
import { Crosshair, TrendingUp, BarChart3, Radio } from 'lucide-react';

const App: React.FC = () => {
  const [selectedStock, setSelectedStock] = useState<StockData | null>(null);

  // Initial Filter State
  const [filter, setFilter] = useState<SniperFilter>({
    minRsi: 0,
    maxRsi: 100,
    minVolume: 0,
    signals: [],
    onlyUptrend: false
  });

  // Filter Logic
  const filteredStocks = useMemo(() => {
    return MOCK_STOCKS.filter(stock => {
      // RSI Filter
      if (stock.rsi < filter.minRsi || stock.rsi > filter.maxRsi) return false;

      // Trend Filter
      if (filter.onlyUptrend && stock.price <= stock.ma50) return false;

      // Signal Filter (OR logic: if stock has ANY of the selected signals)
      if (filter.signals.length > 0) {
        if (!filter.signals.includes(stock.signal)) return false;
      }

      return true;
    });
  }, [filter]);

  // Stats for the Dashboard Header
  const breakoutCount = MOCK_STOCKS.filter(s => s.signal === SignalType.BREAKOUT).length;
  const avgSentiment = MOCK_STOCKS.reduce((acc, s) => acc + (s.changePercent > 0 ? 1 : 0), 0) / MOCK_STOCKS.length * 100;

  return (
    <div className="min-h-screen bg-crypto-bg text-crypto-text pb-20">

      {/* Navbar */}
      <nav className="h-16 border-b border-crypto-border bg-crypto-card/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-crypto-accent rounded flex items-center justify-center neon-glow">
