import { StockData, Trend, SignalType } from './types';

const SECTORS = ['新能源', '半导体', '白酒', '医药', '人工智能', '券商', '房地产'];
const NAMES = [
  '贵州茅台', '宁德时代', '比亚迪', '五粮液', '隆基绿能', 
  '东方财富', '中芯国际', '恒瑞医药', '科大讯飞', '紫光国微',
  '迈瑞医疗', '招商银行', '中国平安', '美的集团', '格力电器',
  '海康威视', '立讯精密', '万华化学', '片仔癀', '韦尔股份'
];

const SYMBOLS = [
  '600519', '300750', '002594', '000858', '601012',
  '300059', '688981', '600276', '002230', '002049',
  '300760', '600036', '601318', '000333', '000651',
  '002415', '002475', '600309', '600436', '603501'
];

const generateHistory = (startPrice: number, points: number = 20) => {
  let current = startPrice;
  const data = [];
  for (let i = 0; i < points; i++) {
    const change = (Math.random() - 0.5) * (startPrice * 0.05);
    current += change;
    data.push({ time: `${i}:00`, value: current });
  }
  return data;
};

export const MOCK_STOCKS: StockData[] = NAMES.map((name, index) => {
  const basePrice = Math.random() * 500 + 10;
  const changeP = (Math.random() * 20) - 10; // -10% to +10%

  // Logic to assign signals based on random indicators
  const rsi = Math.floor(Math.random() * 100);
  let signal = SignalType.NONE;
  let trend = Trend.SIDEWAYS;

  // Simulate Trend
  const ma20 = basePrice * (1 + (Math.random() - 0.5) * 0.1);
  const ma50 = basePrice * (1 + (Math.random() - 0.5) * 0.15);
  // Simple simulation for EMA being slightly more reactive or similar to MA
  const ema20 = basePrice * (1 + (Math.random() - 0.5) * 0.08); 
  const ema50 = basePrice * (1 + (Math.random() - 0.5) * 0.12);

  if (basePrice > ma20 && ma20 > ma50) trend = Trend.UP;
  else if (basePrice < ma20 && ma20 < ma50) trend = Trend.DOWN;

  // Simulate Signals
  if (changeP > 5 && basePrice > ma20) signal = SignalType.BREAKOUT;
  else if (rsi < 30) signal = SignalType.OVERSOLD;
  else if (rsi > 70 && trend === Trend.UP) signal = SignalType.MOMENTUM;
  else if (changeP > 0 && rsi < 40 && trend === Trend.DOWN) signal = SignalType.REVERSAL;

  return {
    id: SYMBOLS[index],
    symbol: SYMBOLS[index],
    name: name,
    price: parseFloat(basePrice.toFixed(2)),
    changePercent: parseFloat(changeP.toFixed(2)),
    volume: Math.floor(Math.random() * 1000000), // Lots
    marketCap: `${(Math.random() * 2000).toFixed(0)}亿`,
    sector: SECTORS[index % SECTORS.length],
    rsi: rsi,
    macd: {
      diff: Math.random() * 2 - 1,
      dea: Math.random() * 2 - 1,
      histogram: Math.random() * 2 - 1,
    },
    ma20: parseFloat(ma20.toFixed(2)),
    ma50: parseFloat(ma50.toFixed(2)),
    ema20: parseFloat(ema20.toFixed(2)),
    ema50: parseFloat(ema50.toFixed(2)),
    ma200: parseFloat((basePrice * 0.9).toFixed(2)),
    trend: trend,
    signal: signal,
    history: generateHistory(basePrice)
  };
});

import { GoogleGenAI, Type } from "@google/genai";
import { StockData, AIAnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeStockWithGemini = async (stock: StockData): Promise<AIAnalysisResult | string> => {
  if (!process.env.API_KEY) {
    // Return a mock structured response for demo mode
    return {
      recommendation: 'WATCH',
      confidence: 65,
      reasoning: [
        `Demo Mode: API Key missing. Showing simulated analysis.`,
        `RSI is at ${stock.rsi}, suggesting ${stock.rsi > 70 ? 'overbought' : stock.rsi < 30 ? 'oversold' : 'neutral'} conditions.`,
        `Trend is currently ${stock.trend}.`
      ],
      riskLevel: 'MEDIUM'
    };
  }

  const prompt = `
    Analyze the following A-Share stock for a sniper trade setup.
    Stock: ${stock.name} (${stock.symbol})
    Price: ${stock.price}
    Change: ${stock.changePercent}%
    RSI: ${stock.rsi}
    EMA20: ${stock.ema20}
    Trend: ${stock.trend}
    Signal: ${stock.signal}
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            recommendation: { type: Type.STRING, enum: ['BUY', 'SELL', 'WATCH'] },
            confidence: { type: Type.INTEGER, description: "0-100 score of trade quality" },
            reasoning: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3 bullet points explaining the technicals" 
            },
            riskLevel: { type: Type.STRING, enum: ['HIGH', 'MEDIUM', 'LOW'] }
          },
          required: ['recommendation', 'confidence', 'reasoning', 'riskLevel']
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response");
    return JSON.parse(text) as AIAnalysisResult;

  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "System Error: Unable to perform AI analysis.";
  }
};

