const App: React.FC = () => {
  const [stocks, setStocks] = useState<StockData[]>(MOCK_STOCKS);
  const [selectedStock, setSelectedStock] = useState<StockData | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'price', direction: 'desc' });

  // Real-time Data Simulation
  useEffect(() => {
    const interval = setInterval(() => {
      setStocks(prevStocks => prevStocks.map(stock => {
        // Random slight fluctuation
        const fluctuation = (Math.random() - 0.5) * 0.2;
        const newPrice = Math.max(0.01, stock.price + fluctuation);
        const newChange = stock.changePercent + (fluctuation / stock.price) * 100;

        // Update history for sparkline
        const newHistoryPoint = { time: new Date().toLocaleTimeString(), value: newPrice };
        const newHistory = [...stock.history.slice(1), newHistoryPoint];

        return {
          ...stock,
          price: newPrice,
          changePercent: newChange,
          history: newHistory,
          // Recalculate basic signals occasionally (simplified)
          rsi: Math.max(0, Math.min(100, stock.rsi + (Math.random() - 0.5) * 2)) 
        };
      }));
    }, 2500); // Update every 2.5s

    return () => clearInterval(interval);
  }, []);

  // Filter State
  const [filter, setFilter] = useState<SniperFilter>({
    minRsi: 0,
    maxRsi: 100,
    minVolume: 0,
    signals: [],
    onlyUptrend: false,
    priceAboveEma20: false
  });

  // Sort Handler
  const handleSort = (key: SortKey) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  // Filter & Sort Logic
  const filteredAndSortedStocks = useMemo(() => {
    // 1. Filter
    const filtered = stocks.filter(stock => {
      if (stock.rsi < filter.minRsi || stock.rsi > filter.maxRsi) return false;
      if (filter.onlyUptrend && stock.price <= stock.ma50) return false;
      if (filter.priceAboveEma20 && stock.price <= stock.ema20) return false;

      if (filter.signals.length > 0) {
        if (!filter.signals.includes(stock.signal)) return false;
      }
      return true;
    });

    // 2. Sort
    return filtered.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      // Handle string comparison for symbols/signals
      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue) 
          : bValue.localeCompare(aValue);
      }

      // Handle number comparison
      // @ts-ignore
      return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
    });
  }, [stocks, filter, sortConfig]);

  // Dashboard Stats
  const breakoutCount = stocks.filter(s => s.signal === SignalType.BREAKOUT).length;
  const avgSentiment = stocks.reduce((acc, s) => acc + (s.changePercent > 0 ? 1 : 0), 0) / stocks.length * 100;

