import { AnalysisModal } from './components/AnalysisModal';
import { Crosshair, TrendingUp, BarChart3, Radio } from 'lucide-react';

type ViewMode = 'ALL' | 'WATCHLIST';

const App: React.FC = () => {
  const [stocks, setStocks] = useState<StockData[]>(MOCK_STOCKS);
  const [selectedStock, setSelectedStock] = useState<StockData | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'price', direction: 'desc' });
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('ALL');

  // Real-time Data Simulation
  useEffect(() => {
    const interval = setInterval(() => {
      setStocks(prevStocks => prevStocks.map(stock => {
        // Random slight fluctuation
        const fluctuation = (Math.random() - 0.5) * 0.2;
        const newPrice = Math.max(0.01, stock.price + fluctuation);
        const newChange = stock.changePercent + (fluctuation / stock.price) * 100;

        // Update history for sparkline
        const newHistoryPoint = { time: new Date().toLocaleTimeString(), value: newPrice };
        const newHistory = [...stock.history.slice(1), newHistoryPoint];

        return {
          ...stock,
          price: newPrice,
          changePercent: newChange,
          history: newHistory,
          // Recalculate basic signals occasionally (simplified)
          rsi: Math.max(0, Math.min(100, stock.rsi + (Math.random() - 0.5) * 2)) 
        };
      }));
    }, 2500); // Update every 2.5s

    return () => clearInterval(interval);
  }, []);

  // Filter State
  const [filter, setFilter] = useState<SniperFilter>({
    minRsi: 0,
    maxRsi: 100,
    minVolume: 0,
    signals: [],
    onlyUptrend: false,
    priceAboveEma20: false
  });

  // Sort Handler
  const handleSort = (key: SortKey) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const toggleWatchlist = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setWatchlist(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  // Filter & Sort Logic
  const filteredAndSortedStocks = useMemo(() => {
    // 1. View Mode Filter
    let baseList = stocks;
    if (viewMode === 'WATCHLIST') {
      baseList = stocks.filter(s => watchlist.includes(s.id));
    }

    // 2. Filter
    const filtered = baseList.filter(stock => {
      if (stock.rsi < filter.minRsi || stock.rsi > filter.maxRsi) return false;
      if (filter.onlyUptrend && stock.price <= stock.ma50) return false;
      if (filter.priceAboveEma20 && stock.price <= stock.ema20) return false;

      if (filter.signals.length > 0) {
        if (!filter.signals.includes(stock.signal)) return false;
      }
      return true;
    });

    // 3. Sort
    return filtered.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      // Handle string comparison for symbols/signals
      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue) 
          : bValue.localeCompare(aValue);
      }

      // Handle number comparison
      // @ts-ignore
      return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
    });
  }, [stocks, filter, sortConfig, viewMode, watchlist]);

  // Dashboard Stats
  const breakoutCount = stocks.filter(s => s.signal === SignalType.BREAKOUT).length;
  const avgSentiment = stocks.reduce((acc, s) => acc + (s.changePercent > 0 ? 1 : 0), 0) / stocks.length * 100;

  return (
    <div className="min-h-screen bg-crypto-bg text-crypto-text pb-20 font-sans">

      {/* Navbar */}
      <nav className="h-16 border-b border-crypto-border bg-crypto-card/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-crypto-accent rounded flex items-center justify-center neon-glow">
              <Crosshair className="text-white w-5 h-5" />
            </div>
            <span className="font-bold text-xl tracking-tighter text-white">ALPHA<span className="text-crypto-accent">SNIPER</span>_A-SHARE</span>
          </div>
          <div className="flex items-center gap-4 text-xs font-mono text-crypto-muted">
            <div className="flex items-center gap-1">
               <div className="w-2 h-2 bg-crypto-up rounded-full animate-pulse"></div>
               LIVE FEED
            </div>
            <span>INDEX: 3,240.15</span>
            <div className="px-5 py-2 bg-crypto-accent hover:bg-blue-600 text-white font-bold rounded cursor-pointer transition-colors shadow-lg shadow-blue-900/20">
              LOGIN
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8">

        {/* Market Stats Dashboard */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
               <TrendingUp className="w-16 h-16 text-crypto-up" />
            </div>
            <p className="text-crypto-muted text-xs font-mono uppercase">Market Sentiment</p>
            <h3 className="text-2xl font-bold mt-1 text-white">{avgSentiment.toFixed(0)}% <span className="text-sm font-normal text-crypto-muted">Bullish</span></h3>
            <div className="w-full bg-gray-700 h-1 mt-3 rounded-full overflow-hidden">
               <div className="bg-crypto-up h-full transition-all duration-1000" style={{ width: `${avgSentiment}%` }}></div>
            </div>
          </div>

          <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border">
            <div className="flex justify-between items-start">
               <div>
                 <p className="text-crypto-muted text-xs font-mono uppercase">Breakout Signals</p>
                 <h3 className="text-2xl font-bold mt-1 text-crypto-up">{breakoutCount}</h3>
               </div>
               <BarChart3 className="text-crypto-muted w-5 h-5" />
            </div>
          </div>

           <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border">
            <div className="flex justify-between items-start">
               <div>
                 <p className="text-crypto-muted text-xs font-mono uppercase">Vol. Spike</p>
                 <h3 className="text-2xl font-bold mt-1 text-white">12</h3>
               </div>
               <Radio className="text-crypto-accent w-5 h-5 animate-pulse" />
            </div>
          </div>

           <div className="bg-gradient-to-br from-crypto-accent/20 to-crypto-card p-4 rounded-lg border border-crypto-accent/30 flex flex-col justify-center items-center text-center cursor-pointer hover:border-crypto-accent transition-colors" onClick={() => setSelectedStock(stocks[0])}>
              <span className="text-crypto-accent font-bold text-sm uppercase tracking-widest mb-1">Star Pick</span>
              <span className="text-white font-bold text-lg">{stocks[0].name}</span>
              <span className="text-crypto-up text-xs font-mono mt-1">+AI Recommendation</span>
           </div>
        </div>

        {/* Filters */}
        <SniperScope filter={filter} setFilter={setFilter} />

        {/* Results Header with View Toggle */}
        <div className="flex items-center justify-between mb-4 border-b border-crypto-border pb-4">
