             </div>

             {/* View Mode Tabs */}
             <div className="flex bg-crypto-card rounded p-1 border border-crypto-border">
               <button 
                  onClick={() => setViewMode('ALL')}
                  className={`px-4 py-1.5 rounded text-xs font-bold transition-all ${viewMode === 'ALL' ? 'bg-crypto-accent text-white shadow-lg' : 'text-crypto-muted hover:text-white'}`}
               >
                 ALL A-SHARES ({stocks.length})
               </button>
               <button 
                  onClick={() => setViewMode('WATCHLIST')}
                  className={`px-4 py-1.5 rounded text-xs font-bold transition-all ${viewMode === 'WATCHLIST' ? 'bg-crypto-accent text-white shadow-lg' : 'text-crypto-muted hover:text-white'}`}
               >
                 WATCHLIST ({watchlist.length})
               </button>
             </div>
           </div>

           <div className="flex items-center gap-4">
             <span className="text-white font-mono text-sm">Results: <span className="text-crypto-accent">{filteredAndSortedStocks.length}</span></span>
             <div className="text-xs text-crypto-muted font-mono flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-crypto-up rounded-full animate-pulse"></span>
                REAL-TIME
             </div>
           </div>
        </div>

        <StockTerminal 
          stocks={filteredAndSortedStocks} 
          onSelectStock={(stock) => setSelectedStock(stock)}
          sortConfig={sortConfig}
          onSort={handleSort}
          watchlist={watchlist}
          onToggleWatchlist={toggleWatchlist}
        />

      </main>

      {/* Footer */}
      <footer className="border-t border-crypto-border mt-12 py-8 text-center text-crypto-muted text-xs font-mono">
        <p>ALPHA SNIPER // A-SHARE INTELLIGENCE</p>
        <p className="mt-2 opacity-50">Invest responsibly. This tool is for informational purposes only.</p>
      </footer>

      {/* Modal */}
      {selectedStock && (
        <AnalysisModal 
          stock={selectedStock} 
          onClose={() => setSelectedStock(null)}
          isWatched={watchlist.includes(selectedStock.id)}
          onToggleWatchlist={() => toggleWatchlist(selectedStock.id)}
        />
      )}
