import { AnalysisModal } from './components/AnalysisModal';
import { Crosshair, TrendingUp, BarChart3, Radio, List, Target, Star } from 'lucide-react';

type ViewMode = 'TOP_200' | 'TARGETS' | 'WATCHLIST';

const App: React.FC = () => {
  const [stocks, setStocks] = useState<StockData[]>(MOCK_STOCKS);
  const [selectedStock, setSelectedStock] = useState<StockData | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'price', direction: 'desc' });
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('TOP_200');

  // Real-time Data Simulation
  useEffect(() => {
    const interval = setInterval(() => {
      setStocks(prevStocks => prevStocks.map(stock => {
        // Random slight fluctuation
        const fluctuation = (Math.random() - 0.5) * 0.2;
        const newPrice = Math.max(0.01, stock.price + fluctuation);
        const newChange = stock.changePercent + (fluctuation / stock.price) * 100;

        // Update history for sparkline
        const newHistoryPoint = { time: new Date().toLocaleTimeString(), value: newPrice };
        const newHistory = [...stock.history.slice(1), newHistoryPoint];

        return {
          ...stock,
          price: newPrice,
          changePercent: newChange,
          history: newHistory,
          // Recalculate basic signals occasionally (simplified)
          rsi: Math.max(0, Math.min(100, stock.rsi + (Math.random() - 0.5) * 2)) 
        };
      }));
    }, 2500); // Update every 2.5s

    return () => clearInterval(interval);
  }, []);

  // Filter State
  const [filter, setFilter] = useState<SniperFilter>({
    minRsi: 0,
    maxRsi: 100,
    minVolume: 0,
    signals: [],
    onlyUptrend: false,
    priceAboveEma20: false
  });

  // Sort Handler
  const handleSort = (key: SortKey) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const toggleWatchlist = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setWatchlist(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  // Calculate counts for tabs
  const targetsCount = useMemo(() => {
    return stocks.filter(stock => {
      if (stock.rsi < filter.minRsi || stock.rsi > filter.maxRsi) return false;
      if (filter.onlyUptrend && stock.price <= stock.ma50) return false;
      if (filter.priceAboveEma20 && stock.price <= stock.ema20) return false;
      if (filter.signals.length > 0) {
        if (!filter.signals.includes(stock.signal)) return false;
      }
      return true;
    }).length;
  }, [stocks, filter]);

  // Filter & Sort Logic for Display
  const filteredAndSortedStocks = useMemo(() => {
    let result = stocks;

    // 1. Filter based on View Mode
    if (viewMode === 'TOP_200') {
      // Top 200 mode displays all stocks (assuming input list is the top market cap list)
      // We do not apply Sniper Filters here, showing the raw market
      result = stocks;
    } else if (viewMode === 'TARGETS') {
      // Targets mode applies Sniper Filters
      result = stocks.filter(stock => {
        if (stock.rsi < filter.minRsi || stock.rsi > filter.maxRsi) return false;
        if (filter.onlyUptrend && stock.price <= stock.ma50) return false;
        if (filter.priceAboveEma20 && stock.price <= stock.ema20) return false;
        if (filter.signals.length > 0) {
          if (!filter.signals.includes(stock.signal)) return false;
        }
        return true;
      });
    } else if (viewMode === 'WATCHLIST') {
      // Watchlist mode
      result = stocks.filter(s => watchlist.includes(s.id));
    }

    // 2. Sort
    return result.sort((a, b) => {
      const aValue = a[sortConfig.key];
      const bValue = b[sortConfig.key];

      // Handle string comparison for symbols/signals
      if (typeof aValue === 'string' && typeof bValue === 'string') {
        return sortConfig.direction === 'asc' 
          ? aValue.localeCompare(bValue) 
          : bValue.localeCompare(aValue);
      }

      // Handle number comparison
      // @ts-ignore
      return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
    });
  }, [stocks, filter, sortConfig, viewMode, watchlist]);

  // Dashboard Stats
  const breakoutCount = stocks.filter(s => s.signal === SignalType.BREAKOUT).length;
  const avgSentiment = stocks.reduce((acc, s) => acc + (s.changePercent > 0 ? 1 : 0), 0) / stocks.length * 100;

  return (
    <div className="min-h-screen bg-crypto-bg text-crypto-text pb-20 font-sans">

      {/* Navbar */}
      <nav className="h-16 border-b border-crypto-border bg-crypto-card/50 backdrop-blur-md sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-crypto-accent rounded flex items-center justify-center neon-glow">
              <Crosshair className="text-white w-5 h-5" />
            </div>
            <span className="font-bold text-xl tracking-tighter text-white">ALPHA<span className="text-crypto-accent">SNIPER</span>_A-SHARE</span>
          </div>
          <div className="flex items-center gap-4 text-xs font-mono text-crypto-muted">
            <div className="flex items-center gap-1">
               <div className="w-2 h-2 bg-crypto-up rounded-full animate-pulse"></div>
               LIVE FEED
            </div>
            <span>INDEX: 3,240.15</span>
            <div className="px-5 py-2 bg-crypto-accent hover:bg-blue-600 text-white font-bold rounded cursor-pointer transition-colors shadow-lg shadow-blue-900/20">
              LOGIN
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8">

        {/* Market Stats Dashboard */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
               <TrendingUp className="w-16 h-16 text-crypto-up" />
            </div>
            <p className="text-crypto-muted text-xs font-mono uppercase">Market Sentiment</p>
            <h3 className="text-2xl font-bold mt-1 text-white">{avgSentiment.toFixed(0)}% <span className="text-sm font-normal text-crypto-muted">Bullish</span></h3>
            <div className="w-full bg-gray-700 h-1 mt-3 rounded-full overflow-hidden">
               <div className="bg-crypto-up h-full transition-all duration-1000" style={{ width: `${avgSentiment}%` }}></div>
            </div>
          </div>

          <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border">
            <div className="flex justify-between items-start">
               <div>
                 <p className="text-crypto-muted text-xs font-mono uppercase">Breakout Signals</p>
                 <h3 className="text-2xl font-bold mt-1 text-crypto-up">{breakoutCount}</h3>
               </div>
               <BarChart3 className="text-crypto-muted w-5 h-5" />
            </div>
          </div>

           <div className="bg-crypto-card p-4 rounded-lg border border-crypto-border">
            <div className="flex justify-between items-start">
               <div>
                 <p className="text-crypto-muted text-xs font-mono uppercase">Vol. Spike</p>
                 <h3 className="text-2xl font-bold mt-1 text-white">12</h3>
               </div>
               <Radio className="text-crypto-accent w-5 h-5 animate-pulse" />
            </div>
          </div>

           <div className="bg-gradient-to-br from-crypto-accent/20 to-crypto-card p-4 rounded-lg border border-crypto-accent/30 flex flex-col justify-center items-center text-center cursor-pointer hover:border-crypto-accent transition-colors" onClick={() => setSelectedStock(stocks[0])}>
              <span className="text-crypto-accent font-bold text-sm uppercase tracking-widest mb-1">Star Pick</span>
              <span className="text-white font-bold text-lg">{stocks[0].name}</span>
              <span className="text-crypto-up text-xs font-mono mt-1">+AI Recommendation</span>
           </div>
        </div>

        {/* Filters - Only show when in TARGETS mode or if we want global filters */}
        {/* We keep it visible but it primarily affects the Targets tab */}
        <SniperScope filter={filter} setFilter={setFilter} />

        {/* Tab Navigation */}
        <div className="flex flex-col md:flex-row items-center justify-between mb-4 border-b border-crypto-border pb-1 gap-4">

           {/* Main Tabs */}
           <div className="flex w-full md:w-auto bg-crypto-card/50 rounded-t-lg overflow-hidden border-x border-t border-crypto-border">

              <button 
                onClick={() => setViewMode('TOP_200')}
                className={`flex-1 md:flex-none flex items-center gap-2 px-6 py-4 text-sm font-bold tracking-wide transition-all border-b-2 ${
                   viewMode === 'TOP_200' 
                   ? 'bg-crypto-card border-crypto-accent text-white' 
                   : 'bg-transparent border-transparent text-crypto-muted hover:text-white hover:bg-white/5'
                }`}
              >
                <List className="w-4 h-4" />
                TOP 200 A-SHARE
              </button>

              <button 
                onClick={() => setViewMode('TARGETS')}
                className={`flex-1 md:flex-none flex items-center gap-2 px-6 py-4 text-sm font-bold tracking-wide transition-all border-b-2 ${
                   viewMode === 'TARGETS' 
                   ? 'bg-crypto-card border-crypto-accent text-white' 
                   : 'bg-transparent border-transparent text-crypto-muted hover:text-white hover:bg-white/5'
                }`}
              >
                <Target className="w-4 h-4" />
                TARGETS FOUND
                <span className={`ml-1 text-[10px] px-1.5 py-0.5 rounded-full ${targetsCount > 0 ? 'bg-crypto-accent text-white' : 'bg-crypto-border text-crypto-muted'}`}>
                  {targetsCount}
                </span>
              </button>

              <button 
                onClick={() => setViewMode('WATCHLIST')}
                className={`flex-1 md:flex-none flex items-center gap-2 px-6 py-4 text-sm font-bold tracking-wide transition-all border-b-2 ${
                   viewMode === 'WATCHLIST' 
                   ? 'bg-crypto-card border-crypto-accent text-white' 
                   : 'bg-transparent border-transparent text-crypto-muted hover:text-white hover:bg-white/5'
                }`}
              >
                <Star className="w-4 h-4" />
                WATCHLIST
                <span className="ml-1 text-[10px] bg-crypto-border text-crypto-muted px-1.5 py-0.5 rounded-full">
                  {watchlist.length}
                </span>
              </button>

           </div>

           <div className="hidden md:flex items-center gap-4 px-4 pb-2">
             <div className="text-xs text-crypto-muted font-mono flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-crypto-up rounded-full animate-pulse"></span>
                REAL-TIME
             </div>
           </div>
        </div>

        {/* Content Area */}
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
          <StockTerminal 
            stocks={filteredAndSortedStocks} 
            onSelectStock={(stock) => setSelectedStock(stock)}
            sortConfig={sortConfig}
            onSort={handleSort}
            watchlist={watchlist}
            onToggleWatchlist={toggleWatchlist}
          />
        </div>

      </main>

      {/* Footer */}
      <footer className="border-t border-crypto-border mt-12 py-8 text-center text-crypto-muted text-xs font-mono">
        <p>ALPHA SNIPER // A-SHARE INTELLIGENCE</p>
        <p className="mt-2 opacity-50">Invest responsibly. This tool is for informational purposes only.</p>
      </footer>

      {/* Modal */}
      {selectedStock && (
        <AnalysisModal 
          stock={selectedStock} 
          onClose={() => setSelectedStock(null)}
          isWatched={watchlist.includes(selectedStock.id)}
          onToggleWatchlist={() => toggleWatchlist(selectedStock.id)}
        />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { StockData } from '../types';

interface MarketTickerProps {
  items: StockData[];
}

export const MarketTicker: React.FC<MarketTickerProps> = ({ items }) => {
  // Use the first 15 items for the ticker
  const tickerItems = items.slice(0, 15);

  return (
    <div className="w-full bg-[#0d1117] border-b border-crypto-border overflow-hidden h-8 flex items-center relative z-30">
      <div className="flex animate-scroll whitespace-nowrap hover:pause-animation">
        {/* Duplicate items multiple times for seamless infinite scroll */}
        {[...tickerItems, ...tickerItems, ...tickerItems, ...tickerItems].map((item, i) => (
          <div key={`${item.id}-${i}`} className="inline-flex items-center gap-3 px-6 text-[10px] font-mono border-r border-white/5">
            <span className="text-crypto-muted font-bold">{item.name}</span>
            <span className={item.changePercent >= 0 ? 'text-crypto-up' : 'text-crypto-down'}>
              {item.price.toFixed(2)}
            </span>
            <span className={item.changePercent >= 0 ? 'text-crypto-up' : 'text-crypto-down'}>
              {item.changePercent > 0 ? '↑' : '↓'} {Math.abs(item.changePercent).toFixed(2)}%
            </span>
          </div>
        ))}
      </div>
       <style>{`
        .animate-scroll {
          animation: scroll 40s linear infinite;
        }
        .hover\\:pause-animation:hover {
          animation-play-state: paused;
        }
        @keyframes scroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-25%); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { StockData, Trend, SignalType, SortKey, SortDirection } from '../types';
import { TrendingUp, TrendingDown, Minus, Zap, Eye, ChevronUp, ChevronDown, Star, ChevronLeft, ChevronRight } from 'lucide-react';
import { LineChart, Line, ResponsiveContainer, YAxis } from 'recharts';

interface StockTerminalProps {
  stocks: StockData[];
  onSelectStock: (stock: StockData) => void;
  sortConfig: { key: SortKey; direction: SortDirection };
  onSort: (key: SortKey) => void;
  watchlist: string[];
  onToggleWatchlist: (id: string, e: React.MouseEvent) => void;
}

export const StockTerminal: React.FC<StockTerminalProps> = ({ stocks, onSelectStock, sortConfig, onSort, watchlist, onToggleWatchlist }) => {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(20);

  // Reset to valid page when stocks length changes (e.g. filtering)
  useEffect(() => {
    const maxPage = Math.ceil(stocks.length / itemsPerPage) || 1;
    if (currentPage > maxPage) setCurrentPage(maxPage);
  }, [stocks.length, itemsPerPage]);

  const totalPages = Math.ceil(stocks.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const currentStocks = stocks.slice(startIndex, startIndex + itemsPerPage);

  const getTrendIcon = (trend: Trend) => {
    switch (trend) {
      case Trend.UP: return <TrendingUp className="w-4 h-4 text-crypto-up" />;
      case Trend.DOWN: return <TrendingDown className="w-4 h-4 text-crypto-down" />;
      default: return <Minus className="w-4 h-4 text-crypto-muted" />;
    }
  };

  const getSignalBadge = (signal: SignalType) => {
    switch (signal) {
      case SignalType.BREAKOUT: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-crypto-up/20 text-crypto-up border border-crypto-up/40 font-bold animate-pulse">BREAKOUT</span>;
      case SignalType.REVERSAL: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-purple-500/20 text-purple-400 border border-purple-500/40 font-bold">REVERSAL</span>;
      case SignalType.MOMENTUM: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-blue-500/20 text-blue-400 border border-blue-500/40 font-bold">MOMENTUM</span>;
      case SignalType.OVERSOLD: 
        return <span className="text-[10px] px-2 py-0.5 rounded bg-orange-500/20 text-orange-400 border border-orange-500/40 font-bold">OVERSOLD</span>;
      default: return null;
    }
  };

  const SortIcon = ({ colKey }: { colKey: SortKey }) => {
    if (sortConfig.key !== colKey) return <div className="w-4 h-4" />;
    return sortConfig.direction === 'asc' ? <ChevronUp className="w-3 h-3 text-crypto-accent" /> : <ChevronDown className="w-3 h-3 text-crypto-accent" />;
  };

  const HeaderCell = ({ label, sortKey, align = 'left' }: { label: string, sortKey?: SortKey, align?: string }) => (
    <th 
      className={`px-4 py-3 text-xs font-mono text-crypto-muted uppercase cursor-pointer hover:text-white transition-colors ${align === 'right' ? 'text-right' : align === 'center' ? 'text-center' : 'text-left'}`}
      onClick={() => sortKey && onSort(sortKey)}
    >
      <div className={`flex items-center gap-1 ${align === 'right' ? 'justify-end' : align === 'center' ? 'justify-center' : 'justify-start'}`}>
        {label}
        {sortKey && <SortIcon colKey={sortKey} />}
      </div>
    </th>
  );

  return (
    <div className="bg-crypto-card border border-crypto-border rounded-lg overflow-hidden shadow-lg flex flex-col">
      <div className="overflow-x-auto min-h-[500px]">
        <table className="w-full text-left">
          <thead className="bg-[#1b2129] border-b border-crypto-border sticky top-0 z-10">
            <tr>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase w-10"></th>
              <HeaderCell label="Symbol / Name" sortKey="symbol" />
              <HeaderCell label="Price (¥)" sortKey="price" align="right" />
              <HeaderCell label="24h Change" sortKey="changePercent" align="right" />
              <HeaderCell label="Trend" align="center" />
              <HeaderCell label="RSI(14)" sortKey="rsi" align="center" />
              <HeaderCell label="Sniper Signal" sortKey="signal" align="center" />
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase w-32">Micro Chart</th>
              <th className="px-4 py-3 text-xs font-mono text-crypto-muted uppercase text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-crypto-border/50">
            {currentStocks.map((stock) => {
              const isWatched = watchlist.includes(stock.id);
              return (
                <tr 
                  key={stock.id} 
                  className="hover:bg-white/5 transition-colors cursor-pointer group"
                  onClick={() => onSelectStock(stock)}
                >
                  <td className="px-4 py-3">
                    <button 
                      onClick={(e) => onToggleWatchlist(stock.id, e)}
                      className={`p-1 rounded hover:bg-white/10 ${isWatched ? 'text-yellow-400' : 'text-crypto-muted hover:text-white'}`}
                    >
                      <Star className={`w-4 h-4 ${isWatched ? 'fill-yellow-400' : ''}`} />
                    </button>
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex flex-col">
                      <span className="font-bold text-sm text-white group-hover:text-crypto-accent transition-colors">{stock.name}</span>
                      <span className="text-xs text-crypto-muted font-mono">{stock.symbol}</span>
                    </div>
                  </td>
                  <td className="px-4 py-3 text-right font-mono text-sm">
                    {stock.price.toFixed(2)}
                    <div className="text-[10px] text-crypto-muted">EMA20: {stock.ema20.toFixed(2)}</div>
                  </td>
                  <td className={`px-4 py-3 text-right font-mono text-sm ${stock.changePercent >= 0 ? 'text-crypto-up' : 'text-crypto-down'}`}>
                    {stock.changePercent > 0 ? '+' : ''}{stock.changePercent.toFixed(1)}%
                  </td>
                  <td className="px-4 py-3 text-center">
                    <div className="flex justify-center">{getTrendIcon(stock.trend)}</div>
                  </td>
                  <td className="px-4 py-3 text-center font-mono text-sm">
                    <span className={`${stock.rsi > 70 ? 'text-crypto-down' : stock.rsi < 30 ? 'text-crypto-up' : 'text-crypto-muted'}`}>
                      {stock.rsi.toFixed(1)}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-center">
                    {getSignalBadge(stock.signal)}
                  </td>
                  <td className="px-4 py-3">
                    <div className="h-10 w-28">
                       <ResponsiveContainer width="100%" height="100%">
                         <LineChart data={stock.history}>
                           <Line 
                              type="monotone" 
                              dataKey="value" 
                              stroke={stock.changePercent >= 0 ? '#00c076' : '#ff3b30'} 
                              strokeWidth={2} 
                              dot={false} 
                              isAnimationActive={false}
                            />
                           <YAxis domain={['dataMin', 'dataMax']} hide />
                         </LineChart>
                       </ResponsiveContainer>
                    </div>
                  </td>
                  <td className="px-4 py-3 text-right">
                    <button className="p-2 hover:bg-crypto-accent/20 rounded-full text-crypto-accent transition-colors" title="Analyze">
                      <Zap className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Pagination Controls */}
      <div className="border-t border-crypto-border p-4 bg-[#1b2129] flex items-center justify-between sticky bottom-0 z-10">
         <div className="flex items-center gap-2 text-xs text-crypto-muted">
            <span>Show</span>
            <select 
              value={itemsPerPage} 
              onChange={(e) => setItemsPerPage(Number(e.target.value))}
              className="bg-crypto-bg border border-crypto-border rounded px-2 py-1 text-white focus:outline-none focus:border-crypto-accent cursor-pointer"
            >
              <option value={10}>10</option>
              <option value={20}>20</option>
              <option value={50}>50</option>
              <option value={100}>100</option>
            </select>
            <span>rows per page</span>
         </div>

         {stocks.length > 0 && (
           <div className="flex items-center gap-2">
              <span className="text-xs text-crypto-muted mr-2">
                 Page {currentPage} of {totalPages || 1}
              </span>
              <button 
                 onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                 disabled={currentPage === 1}
                 className="p-1.5 rounded bg-crypto-bg border border-crypto-border hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-white"
              >
                 <ChevronLeft className="w-4 h-4" />
              </button>
              <button 
                 onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                 disabled={currentPage === totalPages || totalPages === 0}
                 className="p-1.5 rounded bg-crypto-bg border border-crypto-border hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-white"
              >
                 <ChevronRight className="w-4 h-4" />
              </button>
           </div>
         )}
      </div>

      {stocks.length === 0 && (
         <div className="p-12 text-center text-crypto-muted flex flex-col items-center">
           <Eye className="w-12 h-12 mb-4 opacity-50" />
           <p>No targets found in current scope.</p>
           <p className="text-xs mt-2">Adjust filters to widen net.</p>
         </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { MOCK_STOCKS } from './constants';
import { StockData, SniperFilter, SignalType, SortKey, SortDirection } from './types';
import { SniperScope } from './components/SniperScope';
import { StockTerminal } from './components/StockTerminal';
import { AnalysisModal } from './components/AnalysisModal';
import { MarketTicker } from './components/MarketTicker';
import { Crosshair, TrendingUp, BarChart3, Radio, List, Target, Star } from 'lucide-react';

type ViewMode = 'TOP_200' | 'TARGETS' | 'WATCHLIST';

const App: React.FC = () => {
  const [stocks, setStocks] = useState<StockData[]>(MOCK_STOCKS);
  const [selectedStock, setSelectedStock] = useState<StockData | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ key: 'changePercent', direction: 'desc' });
  const [watchlist, setWatchlist] = useState<string[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('TOP_200');

  // Real-time Data Simulation
  useEffect(() => {
    // Update every 1.5 seconds for a smoother feel
    const interval = setInterval(() => {
      setStocks(prevStocks => prevStocks.map(stock => {
        // More subtle fluctuation for "smooth" feel
        const isVolatile = Math.random() > 0.8;
        const volatility = isVolatile ? 0.3 : 0.05;
