                   <div className="space-y-2">
                     {result.reasoning.map((reason, idx) => (
                       <div key={idx} className="flex gap-3 text-sm text-gray-300">
                         <div className="min-w-[4px] h-[4px] mt-2 rounded-full bg-crypto-accent" />
