import { StockData } from '../types';
import { MOCK_STOCKS } from '../constants';

type StockUpdateListener = (data: StockData[]) => void;
type ConnectionStatusListener = (isConnected: boolean) => void;

class StockWebSocketService {
  private subscribers: StockUpdateListener[] = [];
  private statusListeners: ConnectionStatusListener[] = [];
  private isConnected = false;
  private intervalId: number | null = null;

  // Internal state acting as the "Server" source of truth
  private currentData: StockData[] = [];

  constructor() {
    // Deep copy initial data to ensure server state is isolated
    this.currentData = JSON.parse(JSON.stringify(MOCK_STOCKS));
  }

  /**
   * Simulates establishing a WebSocket connection
   */
  connect() {
    if (this.isConnected) return;

    // Simulate network handshake delay
    setTimeout(() => {
      this.isConnected = true;
      this.notifyStatus(true);
      this.startStream();
      // Send immediate snapshot upon connection
      this.notifySubscribers(this.currentData);
    }, 800);
  }

  /**
   * Closes the connection
   */
  disconnect() {
    this.isConnected = false;
    this.notifyStatus(false);
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  /**
   * Subscribe to stock updates
   */
  subscribe(callback: StockUpdateListener): () => void {
    this.subscribers.push(callback);
    // If already connected, send current state immediately
    if (this.isConnected) {
        callback(this.currentData);
    }
    return () => {
      this.subscribers = this.subscribers.filter(cb => cb !== callback);
    };
  }

  /**
   * Listen to connection status changes
   */
  onStatusChange(callback: ConnectionStatusListener): () => void {
    this.statusListeners.push(callback);
    return () => {
        this.statusListeners = this.statusListeners.filter(cb => cb !== callback);
    }
  }

  private notifyStatus(status: boolean) {
    this.statusListeners.forEach(cb => cb(status));
  }

  private notifySubscribers(data: StockData[]) {
    this.subscribers.forEach(cb => cb(data));
  }

  /**
   * Simulates the server pushing data frames
   */
  private startStream() {
    if (this.intervalId) clearInterval(this.intervalId);

    this.intervalId = window.setInterval(() => {
      if (!this.isConnected) return;

      // Generate next frame of data
      const updates = this.currentData.map(stock => {
        // Market Mechanics Simulation
        const isVolatile = Math.random() > 0.85; // 15% chance of high volatility
        const volatility = isVolatile ? 0.4 : 0.08;

        // Random walk direction bias based on current trend
        let bias = 0;
        if (stock.trend === 'UP') bias = 0.05;
        if (stock.trend === 'DOWN') bias = -0.05;

        const changeDir = (Math.random() - 0.5) + bias;

        const priceChange = stock.price * (changeDir * volatility * 0.01);
        const newPrice = Math.max(0.01, stock.price + priceChange);

        // Update percentage relative to the day's "open" (simplified here as cumulative)
        // In a real app, changePercent is usually (current - open) / open
        // Here we just accumulate the shift for the visual effect
        const newChangePercent = stock.changePercent + (priceChange / stock.price) * 100;

        // Update Sparkline History
        const newHistoryPoint = { time: new Date().toLocaleTimeString(), value: newPrice };
        // Keep last 20 points
        const newHistory = [...stock.history.slice(1), newHistoryPoint];

        // Update Technical Indicators
        const rsiChange = (Math.random() - 0.5) * 3;
        const newRsi = Math.max(0, Math.min(100, stock.rsi + rsiChange));

        // EMA Approximation
        const k = 2 / (20 + 1);
        const newEma20 = (newPrice * k) + (stock.ema20 * (1 - k));

        return {
          ...stock,
          price: newPrice,
          changePercent: newChangePercent,
          history: newHistory,
          rsi: newRsi,
          ema20: newEma20
        };
      });

      this.currentData = updates;
      this.notifySubscribers(updates);
    }, 1500); // 1.5s refresh rate
  }
}

